public String reverseString(String str) {
    if (str == null) return null;
    return new StringBuilder(str)
            .reverse()
.toString();
}

def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num ** 0.5) + 1):
        if num % i == 0:
            return False
    return True

